jQuery(function($) { //jQuery passed in as first param, so you can use $ inside

	function isValidEmailAddress(emailAddress) {
		var pattern = new RegExp(/^(("[\w-\s]+")|([\w-]+(?:\.[\w-]+)*)|("[\w-\s]+")([\w-]+(?:\.[\w-]+)*))(@((?:[\w-]+\.)*\w[\w-]{0,66})\.([a-z]{2,6}(?:\.[a-z]{2})?)$)|(@\[?((25[0-5]\.|2[0-4][0-9]\.|1[0-9]{2}\.|[0-9]{1,2}\.))((25[0-5]|2[0-4][0-9]|1[0-9]{2}|[0-9]{1,2})\.){2}(25[0-5]|2[0-4][0-9]|1[0-9]{2}|[0-9]{1,2})\]?$)/i);
		return pattern.test(emailAddress);
	};


	// Put cursor in post code box
	$('#postcode').focus();

	$("form").bind("keypress", function (e) {
		if (e.keyCode == 13) {
			return false;
		}
	});



	// Check potcode
	var postcode = null;
	$('#postcode').keyup(function(){
		postcode = $(this).val();
		postcode = postcode.replace(' ','');
		postcodelen = postcode.length;
		if(postcodelen >= 5 && postcodelen <= 7){
			var validpostcode = null;
			validpostcode = postcode.substr(0, postcode.length - 3) + postcode.substr(postcode.length - 3).toUpperCase();
			var endpostcode = validpostcode.substr(validpostcode.length - 3);
			if(endpostcode.match('[0-9][A-Z][A-Z]')){


				$.get('result.php?postcode=' + validpostcode + '&r=' + Math.floor(Math.random()*101), function(data) {
					if(data != 'no results' && data != 'invalid' ){

						$('#sub_postcode').val(validpostcode);
						$('#housenn').html(data);
						$('#searchpostcode .approved').fadeIn('fast');
						$('#searchhouseno').fadeIn('fast').css('display', 'block !important');
						$('#housenn').focus();
						$('#alert').hide();
					} else {
						$('#alert').html('');
						$('#alert').show();
						$('#alert').html('Post code not found please check and try again');
					}				  
				});


			} else {
				$('#searchpostcode .approved').hide();
				$('#searchhouseno').hide();					
			}
		} else {
			$('#searchpostcode .approved').hide();
			$('#searchhouseno').hide();
			$('#searchhouseno .approved').hide();
			$('#searchbutton').hide();
		}
	});

	$('#housenn').change(function(){

		if($(this).val().length > 0){
			$('#searchhouseno .approved').fadeIn('fast');
			$('#searchbutton').fadeIn('fast').css('display', 'block !important');
			$('#sub_houseno').val($('#housenn option:selected').html());
			var colldaydata = $('#housenn').val();
			var colldaydata = colldaydata.split('-');
			$('#sub_collday').val( colldaydata[1] );
		} else {
			$('#searchhouseno .approved').hide();
			$('#searchbutton').hide();
		}

	});



	$('#not_cta').click(function(e){
		$("#notifications").animate({top:'0px', right:'5%'}, 250);
	});
	$('.close').click(function(e){
		$("#notifications").animate({top:'-1000px', right:'5%'}, 250);
	});


	$('.subscribe').click(function(e){
		e.preventDefault();

		var email = $('#sub_email').attr('value');
		var postcode = $('#sub_postcode').attr('value');
		var houseno = $('#sub_houseno').attr('value');
		var collday = $('#sub_collday').attr('value');

		// Validate email
		if(isValidEmailAddress(email)){
			// Generate url
			var url = "subscribe.php?ajax=true&email=" + email + "&postcode=" + postcode+"&houseno=" + houseno+"&collday=" + collday;
			// Call submission page
			$.ajax({
				url: url,
				context: document.body,
				success: function(data){
					if(data === 'Success! Check your email to confirm sign up.'){
						$('#sub_error').html(data);
						$('#subscribe').hide();			
					} else {
						$('#sub_error').html(data);
					}
				}
			});
		} else {
			// Send back error
			$('#sub_error').html("This is not a valid email address");
		}
	});


});

